INSERT [PreV2].[Descripcion] ([desClave], [desDescrip], [desAbrevia], [desCodigo], [desDescripIng], [desAbreviaIng], [desCodigoIng]) VALUES (	37	,N'De aquí a 2030, reducir la tasa mundial de mortalidad materna a menos de 70 por cada 100,000 nacidos vivos',N'',N'Meta 3.1',N'By 2030, reduce the global maternal mortality ratio to less than 70 per 100 000 live births',N'',N'Target 3.1')
